/// BTCard variant enum.
enum BTCardVariant {
  /// Full card with title, description, optional body, optional footer.
  defaultVariant,

  /// Compact card with title + description only — no footer.
  small,

  /// Card with a top image (180 dp height) followed by default content.
  image,
}

/// BTCard — flexible card organism with three visual variants.
///
/// Figma: node 93:157 (no D/M prefix — all platforms).
///
/// ## Usage:
/// ```dart
/// // Default
/// BTCard(
///   title: 'Order #123',
///   description: 'Placed 26 May 2026',
///   child: Text('Order contents here.'),
///   onCancel: () => Navigator.pop(context),
///   onSubmit: () => handleConfirm(),
/// )
///
/// // Small
/// BTCard.small(
///   title: 'Summary',
///   description: '3 items',
/// )
///
/// // Image — pass any widget via the `image` parameter
/// BTCard.image(
///   image: Image.network(
///     'https://example.com/photo.jpg',
///     width: double.infinity,
///     height: 180,
///     fit: BoxFit.cover,
///   ),
///   title: 'Photo card',
///   description: 'Caption',
///   onSubmit: () => handleAction(),
/// )
///
/// // Custom image widget (shimmer, stack, etc.)
/// BTCard.image(
///   image: Stack(children: [Image.network(...), shimmerOverlay]),
///   title: 'Photo card',
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import 'package:btech_ui/src/components/organisms/card/card.types.dart';
import 'package:flutter/material.dart';

/// Card organism. See file header for usage examples.
class BTCard extends StatelessWidget {
  /// Default card — title + description + optional body + optional footer.
  const BTCard({
    required this.title,
    this.description,
    this.hasFooter = true,
    this.cancelLabel = 'Cancel',
    this.submitLabel = 'Submit',
    this.child,
    this.titleAction,
    this.headerAside,
    this.footer,
    this.onCancel,
    this.onSubmit,
    super.key,
  })  : variant = BTCardVariant.defaultVariant,
        image = null;

  /// Small card — compact padding, no footer.
  const BTCard.small({
    required this.title,
    this.description,
    this.child,
    super.key,
  })  : variant = BTCardVariant.small,
        image = null,
        hasFooter = false,
        cancelLabel = 'Cancel',
        submitLabel = 'Submit',
        titleAction = null,
        headerAside = null,
        footer = null,
        onCancel = null,
        onSubmit = null;

  /// Image card — top image (180 dp) + padded content area below.
  /// Pass any widget via [image] — Image.network, SvgPicture.asset, custom Stack, etc.
  const BTCard.image({
    required this.title,
    this.image,
    this.description,
    this.hasFooter = true,
    this.cancelLabel = 'Cancel',
    this.submitLabel = 'Submit',
    this.child,
    this.titleAction,
    this.headerAside,
    this.footer,
    this.onCancel,
    this.onSubmit,
    super.key,
  }) : variant = BTCardVariant.image;

  final BTCardVariant variant;
  final String title;
  final String? description;

  /// Image widget for the image variant — any widget (Image.network, SvgPicture, custom Stack, etc.).
  /// Rendered at 180 dp height; the card's [Clip.antiAlias] handles the rounded clip.
  final Widget? image;

  final bool hasFooter;
  final String cancelLabel;
  final String submitLabel;

  /// Main body content area (slot3 in Figma).
  final Widget? child;

  /// Widget placed right of the title text (20 dp wide). Default/Image only.
  final Widget? titleAction;

  /// Widget placed right of the entire header block (20 dp wide). Default/Image only.
  final Widget? headerAside;

  /// Replaces the built-in Cancel + Submit footer entirely.
  final Widget? footer;

  final VoidCallback? onCancel;
  final VoidCallback? onSubmit;

  // ── Layout helpers ────────────────────────────────────────────────────────

  bool get _isSmall => variant == BTCardVariant.small;
  bool get _isImage => variant == BTCardVariant.image;

  double get _radius => _isSmall ? 8.0 : 16.0;
  double get _gap => _isSmall ? 12.0 : 16.0;
  EdgeInsets get _padding =>
      _isImage ? EdgeInsets.zero : EdgeInsets.all(_isSmall ? 12.0 : 16.0);

  bool get _showFooter => hasFooter && !_isSmall;

  // ── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    return Container(
      decoration: BoxDecoration(
        color: colors.bg.primary,
        border: Border.all(color: colors.border.primary),
        borderRadius: BorderRadius.circular(_radius),
      ),
      clipBehavior: Clip.antiAlias,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        mainAxisSize: MainAxisSize.min,
        children: [
          // Top image (image variant only) — any widget passed by the consumer
          if (_isImage)
            SizedBox(
              height: 180.0,
              child: image ?? const SizedBox.shrink(),
            ),

          // Content area (padded for image variant, raw for default/small)
          Padding(
            padding: _isImage ? EdgeInsets.all(16.0) : _padding,
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              mainAxisSize: MainAxisSize.min,
              children: [
                _buildHeaderRow(context, colors),
                if (child != null) ...[
                  SizedBox(height: _gap),
                  child!,
                ],
                if (_showFooter) ...[
                  SizedBox(height: _gap),
                  footer ?? _buildFooter(context),
                ],
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildHeaderRow(BuildContext context, BTColorTheme colors) {
    return Row(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Expanded(
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisSize: MainAxisSize.min,
            children: [
              // Title row
              Row(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Expanded(
                    child: Text(
                      title,
                      style: TextStyle(
                        fontFamily: BTTypography.fontFamily,
                        fontSize: _isSmall ? 14.0 : 16.0,
                        fontWeight:
                            _isSmall ? FontWeight.w500 : FontWeight.w700,
                        height: _isSmall ? 16 / 14 : 20 / 16,
                        letterSpacing: 0,
                        color: colors.text.primary,
                      ),
                    ),
                  ),
                  if (titleAction != null && !_isSmall) ...[
                    SizedBox(width: 4.0),
                    SizedBox(width: 20.0, child: titleAction),
                  ],
                ],
              ),
              // Description
              if (description != null) ...[
                SizedBox(height: 4.0),
                Text(
                  description!,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: _isSmall ? 12.0 : 14.0,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    letterSpacing: 0,
                    color: colors.text.secondary,
                  ),
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                ),
              ],
            ],
          ),
        ),
        // Header aside (right of entire header block)
        if (headerAside != null && !_isSmall) ...[
          SizedBox(width: 16.0),
          SizedBox(width: 20.0, child: headerAside),
        ],
      ],
    );
  }

  Widget _buildFooter(BuildContext context) {
    return Row(
      mainAxisAlignment: MainAxisAlignment.end,
      children: [
        BTButton(
          label: cancelLabel,
          variant: BTButtonVariant.secondaryLight,
          size: BTButtonSize.sm,
          onPressed: onCancel,
        ),
        SizedBox(width: 8.0),
        BTButton(
          label: submitLabel,
          variant: BTButtonVariant.primary,
          size: BTButtonSize.sm,
          onPressed: onSubmit,
        ),
      ],
    );
  }
}
